export interface QualityGateConfig {
  type: GateType;
  label: string;
  enabled: boolean;
  required: boolean;
}

export interface QualityGateState {
  type: GateType;
  status: GateStatus;
  result?: string;
  attemptedAt?: string;
}

export interface PlanTaskMetadata {
  goal?: string;
  files?: PlanStepFile[];
  implementationSteps?: ImplementationStep[];
  verificationSteps?: ImplementationStep[];
  dependencies?: string[];
  estimatedMinutes?: number;
  assignee?: string;
  phase?: string;
  riskLevel?: 'low' | 'medium' | 'high';
  qualityGates?: QualityGateConfig[];
  gateStates?: QualityGateState[];
  executionPhase?: 'implementing' | 'reviewing' | 'idle';
}

// CanvasNode.metadata 是 Record<string, unknown>
// PlanTaskMetadata 扩展后在 agent 写入时作为 metadata 的值
// 读取时通过 getTaskMeta(node).qualityGates 强制转型访问
// 无需修改 workbench.ts

const qualityGates = meta.qualityGates;
if (qualityGates !== undefined) {
  if (!Array.isArray(qualityGates)) {
    errors.push(errs(`${prefix}.metadata.qualityGates`, 'must be an array'));
  } else {
    for (let j = 0; j < qualityGates.length; j++) {
      const g = qualityGates[j];
      if (!g || typeof g !== 'object') continue;
      if (!['spec-review', 'code-quality'].includes(g.type)) {
        errors.push(errs(`${prefix}.metadata.qualityGates[${j}].type`, 'must be spec-review or code-quality'));
      }
      if (typeof g.enabled !== 'boolean') {
        errors.push(errs(`${prefix}.metadata.qualityGates[${j}].enabled`, 'must be boolean'));
      }
    }
  }
}

const gateStates = meta.gateStates;
if (gateStates !== undefined) {
  if (!Array.isArray(gateStates)) {
    errors.push(errs(`${prefix}.metadata.gateStates`, 'must be an array'));
  } else {
    const validStatuses = ['pending', 'running', 'passed', 'failed', 'skipped'];
    for (let j = 0; j < gateStates.length; j++) {
      const gs = gateStates[j];
      if (!gs || typeof gs !== 'object') continue;
      if (!validStatuses.includes(gs.status)) {
        errors.push(errs(`${prefix}.metadata.gateStates[${j}].status`, 'must be one of ' + validStatuses.join(', ')));
      }
    }
  }
}

if (meta.executionPhase !== undefined) {
  const validPhases = ['implementing', 'reviewing', 'idle'];
  if (!validPhases.includes(meta.executionPhase as string)) {
    errors.push(errs(`${prefix}.metadata.executionPhase`, 'must be one of ' + validPhases.join(', ')));
  }
}

