router.patch('/node/gate-state', async (req, res) => {
  const { nodeId, type, status, result } = req.body;
  if (!nodeId || !type || !status) {
    return res.status(400).json({ ok: false, error: 'nodeId, type, status required' });
  }
  const state = readState();
  const node = state.canvas.nodes.find((n) => n.id === nodeId);
  if (!node) return res.status(404).json({ ok: false, error: 'node not found' });

  const meta = node.metadata as Record<string, unknown>;
  const gateStates = ((meta.gateStates ?? []) as Array<Record<string, unknown>>);
  const existing = gateStates.find((g) => g.type === type);
  if (existing) {
    existing.status = status;
    if (result) existing.result = result;
    existing.attemptedAt = new Date().toISOString();
  } else {
    gateStates.push({ type, status, result, attemptedAt: new Date().toISOString() });
  }
  meta.gateStates = gateStates;

  writeState(state);
  res.json({ ok: true, state });
});

