function GateConfigSection({
  nodeId,
  gates,
  onUpdate,
}: {
  nodeId: string;
  gates: Array<{ type: string; label: string; enabled: boolean; required: boolean }>;
  onUpdate: (gates: Array<{ type: string; enabled: boolean; required: boolean }>) => Promise<void>;
}) {
  const [local, setLocal] = useState(gates);

  async function toggleGate(index: number, field: 'enabled' | 'required') {
    const next = local.map((g, i) => i === index ? { ...g, [field]: !g[field] } : g);
    setLocal(next);
    await onUpdate(next.map(({ type, enabled, required }) => ({ type, enabled, required })));
  }

  return (
    <section className="mb-6">
      <SectionHeader icon={<Shield size={12} />} title="Quality Gates" count={local.filter(g => g.enabled).length} />
      <div className="mt-3 space-y-2">
        {local.map((gate, i) => (
          <div key={gate.type} className="flex items-center justify-between rounded-lg border border-[var(--border)] bg-[var(--bg-canvas)] px-3 py-2">
            <div className="flex items-center gap-2">
              <button type="button" onClick={() => toggleGate(i, 'enabled')}
                className={`w-8 h-4 rounded-full transition-colors ${gate.enabled ? 'bg-[var(--primary)]' : 'bg-[var(--border)]'}`}>
                <span className={`block w-3 h-3 rounded-full bg-white transition-transform ${gate.enabled ? 'translate-x-4' : 'translate-x-0.5'}`} />
              </button>
              <span className="text-[12px] font-medium text-[var(--text-main)]">{gate.label}</span>
            </div>
            {gate.enabled && (
              <label className="flex items-center gap-1 text-[10px] text-[var(--muted-foreground)] cursor-pointer">
                <input type="checkbox" checked={gate.required}
                  onChange={() => toggleGate(i, 'required')} className="accent-[var(--primary)]" />
                required
              </label>
            )}
          </div>
        ))}
      </div>
    </section>
  );
}

