function GateResultSection({ gateStates }: { gateStates: Array<{ type: string; status: string; result?: string }> }) {
  const ICONS: Record<string, LucideIcon> = {
    passed: CheckCircle2,
    failed: XCircle,
    running: Loader2,
    pending: Circle,
    skipped: Minus,
  };
  return (
    <section className="mb-6">
      <SectionHeader icon={<Shield size={12} />} title="Gate Results" count={gateStates.length} />
      <div className="mt-3 space-y-2">
        {gateStates.map((gs) => {
          const Icon = ICONS[gs.status] ?? Circle;
          const color = GATE_STATUS_COLORS[gs.status] ?? 'var(--muted-foreground)';
          return (
            <div key={gs.type} className="rounded-lg border border-[var(--border)] bg-[var(--bg-canvas)] p-3">
              <div className="flex items-center gap-2">
                <Icon size={14} style={{ color }} />
                <span className="text-[12px] font-bold text-[var(--text-main)]">
                  {gs.type === 'spec-review' ? 'Spec Review' : 'Code Quality'}
                </span>
                <span className="text-[10px] font-bold uppercase" style={{ color }}>{gs.status}</span>
              </div>
              {gs.result && (
                <pre className="mt-2 text-[10px] font-mono text-[var(--muted-foreground)] whitespace-pre-wrap bg-[var(--bg-main)] rounded p-2">
                  {gs.result}
                </pre>
              )}
            </div>
          );
        })}
      </div>
    </section>
  );
}

function ReplanButton({ nodeId, onReplan }: { nodeId: string; onReplan: (id: string) => void }) {
  const { state } = useWorkbench();
  const lowestRating = state.feedback
    .filter((f) => f.nodeId === nodeId && f.rating != null)
    .reduce((min, f) => Math.min(min, f.rating!), 5);

  if (lowestRating > 2) return null;

  return (
    <button
      type="button"
      onClick={() => onReplan(nodeId)}
      className="mt-3 w-full rounded-lg border border-[var(--destructive)]/30 bg-[var(--destructive)]/10 px-3 py-2 text-[12px] font-bold text-[var(--destructive)] transition-colors hover:bg-[var(--destructive)]/20"
    >
      ↻ Re-plan & Re-execute
    </button>
  );
}

