router.post('/replan', async (req, res) => {
  const { nodeId } = req.body;
  if (!nodeId) return res.status(400).json({ ok: false, error: 'nodeId required' });

  const state = readState();
  const node = state.canvas.nodes.find((n) => n.id === nodeId);
  if (!node) return res.status(404).json({ ok: false, error: 'node not found' });

  // Reset node state for re-execution
  node.status = 'pending';
  node.progress = 0;
  const meta = node.metadata as Record<string, unknown>;
  meta.executionPhase = 'idle';
  meta.gateStates = [];

  // Add feedback entry for the agent
  state.feedback.push({
    id: crypto.randomUUID(),
    nodeId,
    text: 'User requested re-plan. Please review and re-execute this task.',
    rating: null,
    section: null,
    stepIndex: null,
    quickAction: 'replan',
    createdAt: new Date().toISOString(),
  });

  writeState(state);
  res.json({ ok: true, state });
});

async function requestReplan(nodeId: string) {
  const res = await fetch(`${BASE}/replan`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ nodeId }),
  });
  const data = await res.json();
  if (data.ok) setState(data.state);
}
